// solution file
#include <iostream>
#include <map>
#include <vector>
using namespace std;

class Solution {
public:
    bool checkProductPair(const vector<int>& seq, int targetProduct) {
        map<int, int> freq;
        for (int num : seq) {
            freq[num] = freq.get(num, 0) + 1;
        }
        for (int i = 0; i < seq.size(); ++i) {
            for (int j = i + 1; j < seq.size(); ++j) {
                if (freq.get(seq[i] * seq[j], 0) == 2 && seq[i] * seq[j] == targetProduct) {
                    return true;
                }
            }
        }
        return false;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    Solution s;
    int n;
    cin >> n;
    vector<int> seq(n);
    for (int i = 0; i < n; ++i) {
        cin >> seq[i];
    }
    int targetProduct;
    cin >> targetProduct;
    cout << boolalpha << s.checkProductPair(seq, targetProduct) << '\n';
    return 0;
}
